blocks.css:
.pm-header-stage{position:relative;height:240px;border-radius:14px;overflow:hidden;background:#000;font-family:'Pretendard',sans-serif}
.pm-h-bg{position:absolute;inset:0;background:linear-gradient(135deg,#0a0a0a 0%,#1a1a1a 60%,#fc6d25 130%);display:flex;align-items:center;justify-content:center}
.pm-h-bg span{font-family:'Pretendard',sans-serif;font-weight:700;font-size:42px;color:rgba(255,255,255,.85);letter-spacing:-.01em}
.pm-h{position:absolute;top:0;left:0;right:0;height:100px;background:transparent;z-index:10;display:flex;align-items:center}
.pm-h-inner{display:flex;align-items:center;justify-content:space-between;width:100%;padding:0 50px}
.pm-logo a{text-decoration:none}
.pm-logo-text{font-family:'Pretendard',sans-serif;font-weight:800;font-size:22px;color:#fff;letter-spacing:-.02em}
.pm-gnb .pm-depth1{display:flex;gap:50px;list-style:none;margin:0;padding:0;font-family:'Pretendard',sans-serif}
.pm-depth1 > li{position:relative}
.pm-depth1 > li > a{color:#fff;text-decoration:none;font-size:17px;font-weight:500;transition:color .3s}
.pm-depth1 > li:hover > a{color:#fc6d25}
.pm-depth2{position:absolute;top:42px;left:50%;transform:translateX(-50%);min-width:150px;background:rgba(0,0,0,.85);padding:10px 0;border-radius:8px;display:none;list-style:none;margin:0}
.pm-depth1 > li:hover .pm-depth2{display:block}
.pm-depth2 li{padding:8px 16px;color:rgba(255,255,255,.85);font-size:14px;white-space:nowrap;cursor:pointer}
.pm-depth2 li:hover{color:#fc6d25}
.pm-burger{width:36px;height:36px;background:transparent;border:0;cursor:pointer;display:flex;flex-direction:column;justify-content:center;gap:5px;padding:0}
.pm-burger span{display:block;width:24px;height:2px;background:#fff;margin-left:auto}
.pm-burger span:nth-child(2){width:16px}
.pm-burger span:nth-child(3){width:22px}

.pm-hero{position:relative;width:100%;height:560px;background:#000;overflow:hidden;border-radius:14px;font-family:'Pretendard',sans-serif}
.pm-hero-video{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;z-index:0}
.pm-hero-overlay{position:absolute;inset:0;background:radial-gradient(ellipse at center,rgba(0,0,0,.3),rgba(0,0,0,.65));z-index:1}
.pm-hero-inner{position:relative;z-index:2;height:100%;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center;padding:0 60px}
.pm-hero-heading{font-family:'Pretendard',sans-serif;font-weight:700;font-size:96px;line-height:1.05;color:#fff;margin:0;letter-spacing:-.03em;animation:pm-rev 1.2s cubic-bezier(.4,0,.2,1) backwards}
.pm-hero-text{font-family:'Pretendard',sans-serif;font-weight:400;font-size:20px;color:rgba(255,255,255,.92);margin:24px 0 0;line-height:1.55;animation:pm-rev 1.2s cubic-bezier(.4,0,.2,1) .2s backwards}
@keyframes pm-rev{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}
.pm-hero-scroll{position:absolute;bottom:30px;left:50%;transform:translateX(-50%);z-index:3;display:flex;flex-direction:column;align-items:center;gap:14px;color:rgba(255,255,255,.85);font-family:'Pretendard',sans-serif;font-size:12px;letter-spacing:.25em}
.pm-hero-scroll .line{width:1px;height:40px;background:rgba(255,255,255,.5);animation:pm-scroll-line 2s ease-in-out infinite}
@keyframes pm-scroll-line{0%,100%{transform:scaleY(.3);transform-origin:top}50%{transform:scaleY(1);transform-origin:top}}

.pm-view{padding:60px 40px;background:#fff;border-radius:14px;font-family:'Pretendard',sans-serif}
.pm-view-flex{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}
.pm-view-card{position:relative;height:520px;border-radius:12px;overflow:hidden;cursor:pointer;transition:transform .4s ease-in-out}
.pm-view-card:hover{transform:translateY(-10px)}
.pm-view-card:nth-child(even){transform:translateY(40px)}
.pm-view-card:nth-child(even):hover{transform:translateY(30px)}
.pm-view-bg{position:absolute;inset:0;background-size:cover;background-position:center;transition:transform .6s ease-in-out}
.pm-view-card:hover .pm-view-bg{transform:scale(1.05)}
.pm-view-card::before{content:'';position:absolute;inset:0;background:linear-gradient(to bottom,rgba(0,0,0,.1) 30%,rgba(0,0,0,.85) 100%);z-index:1}
.pm-view-text{position:absolute;left:0;right:0;bottom:0;padding:40px;color:#fff;z-index:2}
.pm-view-tag{display:block;font-size:14px;font-weight:500;color:#fc6d25;letter-spacing:.04em;margin-bottom:14px}
.pm-view-h2{font-family:'Pretendard',sans-serif;font-weight:700;font-size:32px;color:#fff;margin:0 0 18px;letter-spacing:-.02em;line-height:1.2}
.pm-view-desc{font-size:15px;color:rgba(255,255,255,.88);line-height:1.6;margin:0 0 24px}
.pm-view-more{display:inline-flex;align-items:center;gap:10px;font-size:14px;font-weight:600;color:#fff;text-decoration:none;letter-spacing:.05em;border-bottom:1px solid rgba(255,255,255,.5);padding-bottom:6px}
.pm-view-more i{font-style:normal;transition:transform .3s}
.pm-view-more:hover i{transform:translateX(4px)}

.pm-news{padding:80px 60px;background:#f7f7f7;border-radius:14px;font-family:'Pretendard',sans-serif;max-width:1400px;margin:0 auto}
.pm-news-heading{font-family:'Pretendard',sans-serif;font-weight:700;font-size:48px;color:#000;margin:0 0 60px;letter-spacing:-.02em}
.pm-news-heading .accent{color:#fc6d25}
.pm-news-body{display:grid;grid-template-columns:1fr 1fr;gap:30px}
.pm-news-block{background:#fff;border-radius:14px;padding:36px}
.pm-news-block h4{font-family:'Pretendard',sans-serif;font-weight:700;font-size:22px;color:#000;margin:0 0 28px;letter-spacing:-.01em}
.pm-news-list{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:0}
.pm-news-list li{display:flex;justify-content:space-between;align-items:center;padding:18px 0;border-bottom:1px solid #ebebeb;cursor:pointer;transition:color .3s}
.pm-news-list li:first-child{border-top:1px solid #ebebeb}
.pm-news-list li:hover{color:#fc6d25}
.pm-news-title{font-size:16px;font-weight:500;color:inherit;margin:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.pm-news-date{font-size:13px;color:#999;flex-shrink:0;margin-left:20px;font-family:'Outfit',monospace}
.pm-news-bottom{display:flex;align-items:center;gap:20px;margin-top:30px}
.pm-news-progress{flex:1;height:2px;background:#e8e8e8;overflow:hidden}
.pm-news-progress-inner{width:100%;height:100%;background:#fc6d25;transform:scaleX(.4);transform-origin:left;transition:transform .4s}
.pm-news-handle{display:flex;gap:8px}
.pm-news-handle button{width:36px;height:36px;border-radius:50%;background:transparent;border:1px solid #d0d0d0;cursor:pointer;position:relative;transition:all .3s}
.pm-news-handle button:hover{background:#000;border-color:#000}
.pm-news-handle .prev::before,.pm-news-handle .next::before{content:'';position:absolute;top:50%;left:50%;width:8px;height:8px;border-top:1.5px solid #333;border-right:1.5px solid #333}
.pm-news-handle .prev::before{transform:translate(-30%,-50%) rotate(-135deg)}
.pm-news-handle .next::before{transform:translate(-70%,-50%) rotate(45deg)}
.pm-news-handle button:hover::before{border-color:#fff}

.pm-partners{padding:80px 0;background:#fff;border-radius:14px;font-family:'Pretendard',sans-serif;overflow:hidden}
.pm-partners-h{font-family:'Pretendard',sans-serif;font-weight:700;font-size:42px;color:#000;text-align:center;margin:0 0 50px;letter-spacing:-.02em}
.pm-partners-h .accent{color:#fc6d25}
.pm-partners-row{overflow:hidden;mask-image:linear-gradient(to right,transparent 0,#000 80px,#000 calc(100% - 80px),transparent 100%);-webkit-mask-image:linear-gradient(to right,transparent 0,#000 80px,#000 calc(100% - 80px),transparent 100%);margin-bottom:24px}
.pm-partners-track{display:flex;gap:60px;width:max-content;align-items:center}
.pm-track-1{animation:pm-rolling-l 30s linear infinite}
.pm-track-2{animation:pm-rolling-r 28s linear infinite}
@keyframes pm-rolling-l{from{transform:translateX(0)}to{transform:translateX(-50%)}}
@keyframes pm-rolling-r{from{transform:translateX(-50%)}to{transform:translateX(0)}}
.pm-partners-track img{height:50px;width:auto;object-fit:contain;flex-shrink:0;filter:grayscale(1);opacity:.7;transition:filter .3s,opacity .3s}
.pm-partners-track img:hover{filter:grayscale(0);opacity:1}

.pm-footer{background:#1a1a1a;color:#888;font-family:'Pretendard',sans-serif;border-radius:14px;overflow:hidden;position:relative;padding:60px 50px 30px}
.pm-footer-top{display:flex;justify-content:space-between;gap:40px;padding-bottom:40px;border-bottom:1px solid rgba(255,255,255,.1);margin-bottom:30px}
.pm-footer-sitemap{display:grid;grid-template-columns:repeat(4,1fr);gap:40px;flex:1}
.pm-footer-sitemap dl{margin:0}
.pm-footer-sitemap dt{font-weight:700;font-size:15px;color:#fff;margin-bottom:18px;letter-spacing:-.01em}
.pm-footer-sitemap dt a{color:inherit;text-decoration:none}
.pm-footer-sitemap dd{font-size:13px;color:#888;margin:8px 0;cursor:pointer;transition:color .3s}
.pm-footer-sitemap dd:hover{color:#fc6d25}
.pm-footer-right{display:flex;flex-direction:column;gap:16px;align-items:flex-end}
.pm-footer-link{list-style:none;margin:0;padding:0;display:flex;gap:18px}
.pm-footer-link a{color:#aaa;text-decoration:none;font-size:13px;transition:color .3s}
.pm-footer-link li.active a{color:#fff;font-weight:600}
.pm-footer-link a:hover{color:#fc6d25}
.pm-footer-family{background:transparent;color:#aaa;border:1px solid rgba(255,255,255,.2);border-radius:4px;padding:8px 14px;font-size:13px;font-family:inherit;width:200px}
.pm-footer-bottom{display:flex;justify-content:space-between;align-items:flex-end;gap:20px;flex-wrap:wrap}
.pm-footer-company{font-size:13px;color:#888;line-height:1.7;margin:0;letter-spacing:-.01em}
.pm-footer-copy{font-family:'Outfit',monospace;font-size:12px;color:#666;margin:0}
.pm-btn-top{position:absolute;right:50px;bottom:80px;width:48px;height:48px;border-radius:50%;background:transparent;border:1px solid rgba(255,255,255,.3);color:#fff;cursor:pointer;font-size:18px;transition:all .3s}
.pm-btn-top:hover{background:#fc6d25;border-color:#fc6d25}
